CREATE TABLE IF NOT EXISTS roles (id INT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(30) UNIQUE NOT NULL);
CREATE TABLE IF NOT EXISTS users (id INT AUTO_INCREMENT PRIMARY KEY, role_id INT NOT NULL, name VARCHAR(120) NOT NULL, email VARCHAR(160) UNIQUE NOT NULL, password VARCHAR(255) NOT NULL, phone VARCHAR(30), status ENUM('active','blocked') DEFAULT 'active', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY(role_id) REFERENCES roles(id));
CREATE TABLE IF NOT EXISTS students (id INT AUTO_INCREMENT PRIMARY KEY, user_id INT UNIQUE NOT NULL, roll_no VARCHAR(60), course VARCHAR(100), FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS librarians (id INT AUTO_INCREMENT PRIMARY KEY, user_id INT UNIQUE NOT NULL, employee_code VARCHAR(60), FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS library_tables (id INT AUTO_INCREMENT PRIMARY KEY, table_code VARCHAR(20) UNIQUE NOT NULL, floor_no INT DEFAULT 1, zone VARCHAR(60) DEFAULT 'A', capacity INT DEFAULT 1, status ENUM('available','maintenance','inactive') DEFAULT 'available', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS bookings (id INT AUTO_INCREMENT PRIMARY KEY, student_id INT NOT NULL, table_id INT NOT NULL, duration_days INT NOT NULL, amount DECIMAL(10,2) NOT NULL, status ENUM('pending','accepted','rejected','expired') DEFAULT 'pending', start_date DATE NULL, expiry_date DATE NULL, rejection_reason TEXT NULL, reviewed_by INT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP, INDEX(table_id,status,expiry_date), FOREIGN KEY(student_id) REFERENCES users(id), FOREIGN KEY(table_id) REFERENCES library_tables(id), FOREIGN KEY(reviewed_by) REFERENCES users(id));
CREATE TABLE IF NOT EXISTS payments (id INT AUTO_INCREMENT PRIMARY KEY, booking_id INT UNIQUE NOT NULL, transaction_id VARCHAR(120) UNIQUE NOT NULL, method ENUM('UPI_QR','DYNAMIC_QR') DEFAULT 'UPI_QR', amount DECIMAL(10,2) NOT NULL, status ENUM('pending','verified','rejected') DEFAULT 'pending', paid_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY(booking_id) REFERENCES bookings(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS password_resets (id INT AUTO_INCREMENT PRIMARY KEY, user_id INT NOT NULL, token VARCHAR(128) UNIQUE NOT NULL, otp VARCHAR(10), expires_at DATETIME NOT NULL, used_at DATETIME NULL, FOREIGN KEY(user_id) REFERENCES users(id) ON DELETE CASCADE);
CREATE TABLE IF NOT EXISTS email_logs (id INT AUTO_INCREMENT PRIMARY KEY, user_id INT NULL, recipient VARCHAR(160) NOT NULL, subject VARCHAR(255) NOT NULL, body MEDIUMTEXT NOT NULL, status ENUM('queued','sent','failed') DEFAULT 'queued', error TEXT NULL, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS themes (id INT AUTO_INCREMENT PRIMARY KEY, name VARCHAR(60) UNIQUE NOT NULL, slug VARCHAR(60) UNIQUE NOT NULL, primary_color VARCHAR(20), accent_color VARCHAR(20));
CREATE TABLE IF NOT EXISTS activity_logs (id INT AUTO_INCREMENT PRIMARY KEY, user_id INT NULL, action VARCHAR(255) NOT NULL, ip_address VARCHAR(60), created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);
